import React from 'react';
import { Task } from '../types';
import { calculatePriorityScore, formatTime, getFormattedDate } from '../utils';
import { Trash2, Pencil, CheckCircle2 } from 'lucide-react';

interface WorkListProps {
  tasks: Task[];
  onDelete: (id: string) => void;
  onEdit: (task: Task) => void;
  isHistory?: boolean;
}

export const WorkList: React.FC<WorkListProps> = ({ tasks, onDelete, onEdit, isHistory = false }) => {

  // Grouping Logic
  let groupedTasks: Record<string, Task[]> = {};

  if (isHistory) {
      // Group by Date for History
      groupedTasks = tasks
        .filter(t => t.isCompleted)
        .reduce((acc, task) => {
            // Use completedAt if available, otherwise fallback to updatedAt logic or createdAt
            let dateKey = 'Unknown Date';
            if (task.completedAt) {
                dateKey = task.completedAt.split('T')[0];
            } else if (task.workLogs && task.workLogs.length > 0) {
                // Infer from last work log
                const lastLog = task.workLogs[task.workLogs.length - 1];
                dateKey = new Date(lastLog.startedAt).toISOString().split('T')[0];
            } else {
                // Fallback to creation date
                dateKey = task.createdAt.split('T')[0];
            }

            if (!acc[dateKey]) acc[dateKey] = [];
            acc[dateKey].push(task);
            return acc;
        }, {} as Record<string, Task[]>);

      // Sort tasks within groups by time (desc)
      Object.keys(groupedTasks).forEach(key => {
          groupedTasks[key].sort((a, b) => {
             const timeA = a.completedAt ? new Date(a.completedAt).getTime() : new Date(a.createdAt).getTime();
             const timeB = b.completedAt ? new Date(b.completedAt).getTime() : new Date(b.createdAt).getTime();
             return timeB - timeA;
          });
      });

  } else {
      // Group by Category for Active List
      const uniqueCategories = Array.from(new Set(tasks.map(t => t.category))) as string[];
      groupedTasks = uniqueCategories.reduce((acc, category) => {
        const categoryTasks = tasks
            .filter(t => t.category === category && !t.isCompleted)
            .sort((a, b) => {
                const scoreA = calculatePriorityScore(a.impact, a.urgency, a.effort, a.dueDate, a.isDomino, a.isBlocked);
                const scoreB = calculatePriorityScore(b.impact, b.urgency, b.effort, b.dueDate, b.isDomino, b.isBlocked);
                return scoreB - scoreA;
            });
        if (categoryTasks.length > 0) {
            acc[category] = categoryTasks;
        }
        return acc;
      }, {} as Record<string, Task[]>);
  }

  // Sort Keys (Categories alphabetically or Dates descending)
  const sortedKeys = isHistory 
    ? Object.keys(groupedTasks).sort((a, b) => new Date(b).getTime() - new Date(a).getTime())
    : Object.keys(groupedTasks).sort();

  return (
    <div className="h-full flex flex-col min-h-[500px] w-full">
      <div className="flex-1 overflow-y-auto space-y-8 pr-2 pb-4">

        {sortedKeys.length === 0 && (
             <div className="flex flex-col items-center justify-center h-full text-zinc-400 dark:text-zinc-600 gap-2">
                <span className="text-xl font-bold">{isHistory ? '완료된 작업이 없습니다' : '대기 중인 작업이 없습니다'}</span>
             </div>
        )}

        {sortedKeys.map((groupKey) => {
          const catTasks = groupedTasks[groupKey];
          return (
          <div key={groupKey} className="relative">
            {/* Sticky Header */}
            <div className="flex items-center justify-between gap-3 mb-4 sticky top-0 bg-[#F4F4F5]/90 dark:bg-[#18181B]/90 backdrop-blur-xl py-3 px-5 z-20 rounded-2xl border border-white/20 dark:border-white/5 shadow-sm mx-1">
                <div className="flex items-center gap-3">
                    <span className="text-lg font-black text-zinc-800 dark:text-zinc-200 uppercase tracking-widest">
                        {isHistory ? groupKey : groupKey}
                    </span>
                    <span className="bg-zinc-200 dark:bg-zinc-700 px-2.5 py-0.5 rounded-lg text-xs font-bold text-zinc-600 dark:text-zinc-400">{catTasks.length}</span>
                </div>
            </div>

            <div className="space-y-4 px-1">
              {catTasks.map(task => {
                 const score = calculatePriorityScore(task.impact, task.urgency, task.effort, task.dueDate, task.isDomino, task.isBlocked);
                 return (
                    <div key={task.id} className={`group flex justify-between items-center p-5 md:p-6 bg-white dark:bg-zinc-800 rounded-3xl transition-all border shadow-sm hover:shadow-md cursor-default ${isHistory ? 'opacity-75 border-zinc-100 dark:border-zinc-800' : 'border-zinc-200 dark:border-zinc-700 hover:border-orange-300 dark:hover:border-orange-700'}`}>
                        <div className="flex-1 min-w-0 pr-6">
                            <div className="flex items-center gap-3 mb-1">
                                <span className={`text-lg md:text-xl font-bold truncate ${task.isCompleted ? 'text-zinc-400 dark:text-zinc-500 line-through decoration-2 decoration-zinc-300 dark:decoration-zinc-700' : (task.isBlocked ? 'text-zinc-400 dark:text-zinc-500 line-through decoration-zinc-300 dark:decoration-zinc-700' : 'text-zinc-900 dark:text-zinc-100')}`}>
                                    {task.title}
                                </span>
                            </div>
                            <div className="flex gap-2">
                                {task.isDomino && <span className="text-[10px] bg-orange-100 dark:bg-orange-900/50 text-orange-700 dark:text-orange-300 font-extrabold px-2 py-0.5 rounded-full border border-orange-200 dark:border-orange-800">My Core</span>}
                                {isHistory ? (
                                    <span className="text-[10px] text-zinc-400 dark:text-zinc-500 font-bold px-2 py-0.5 rounded-full bg-zinc-100 dark:bg-zinc-700/50 flex items-center gap-1">
                                        <CheckCircle2 size={10} />
                                        {task.category}
                                    </span>
                                ) : (
                                    <span className="text-[10px] text-zinc-400 dark:text-zinc-500 font-bold px-2 py-0.5 rounded-full bg-zinc-100 dark:bg-zinc-700/50">{task.dueDate}</span>
                                )}
                            </div>
                        </div>
                        <div className="flex items-center gap-4 md:gap-8">
                             {isHistory ? (
                                <div className="text-right shrink-0">
                                    <span className="block text-[10px] text-zinc-400 dark:text-zinc-500 font-extrabold uppercase tracking-wider mb-0.5">Total Time</span>
                                    <span className="text-xl font-black text-zinc-700 dark:text-zinc-300 tabular-nums">{formatTime(task.totalTime || 0)}</span>
                                </div>
                             ) : (
                                <div className="text-right shrink-0">
                                    <span className="block text-[10px] text-zinc-400 dark:text-zinc-500 font-extrabold uppercase tracking-wider mb-0.5">Score</span>
                                    <span className={`text-2xl font-black leading-none ${score < 0 ? 'text-zinc-300 dark:text-zinc-600' : 'text-zinc-900 dark:text-white'}`}>{score.toFixed(0)}</span>
                                </div>
                             )}

                             <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                {!isHistory && (
                                    <button 
                                        onClick={() => onEdit(task)} 
                                        className="p-3 text-zinc-400 dark:text-zinc-500 hover:text-zinc-900 dark:hover:text-white hover:bg-zinc-100 dark:hover:bg-zinc-700 rounded-xl transition-all shrink-0"
                                        title="수정"
                                    >
                                        <Pencil size={20} />
                                    </button>
                                )}
                                <button 
                                    onClick={() => onDelete(task.id)} 
                                    className="p-3 text-zinc-400 dark:text-zinc-500 hover:text-red-600 dark:hover:text-red-400 hover:bg-red-50 dark:hover:bg-red-900/30 rounded-xl transition-all shrink-0"
                                    title="삭제"
                                >
                                    <Trash2 size={20} />
                                </button>
                             </div>
                        </div>
                    </div>
                 );
              })}
            </div>
          </div>
        )})}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Plus, Settings, Trash2, Check } from 'lucide-react';
import { TaskFormData, Task } from '../types';
import { calculatePriorityScore, getFormattedDate } from '../utils';

interface AddTaskModalProps {
  isOpen: boolean;
  onClose: () => void;
  onAdd: (data: TaskFormData) => void;
  onUpdate?: (data: TaskFormData) => void;
  taskToEdit?: Task | null;
  categories: string[];
  onAddCategory: (newCategory: string) => void;
  onDeleteCategory: (category: string) => void;
}

const INITIAL_DATA: TaskFormData = {
  title: '',
  category: '', 
  dueDate: getFormattedDate(new Date()),
  impact: 5,
  urgency: 5,
  effort: 5,
  isDomino: false,
  isBlocked: false,
};

export const AddTaskModal: React.FC<AddTaskModalProps> = ({ 
    isOpen, 
    onClose, 
    onAdd, 
    onUpdate,
    taskToEdit,
    categories, 
    onAddCategory, 
    onDeleteCategory 
}) => {
  const [formData, setFormData] = useState<TaskFormData>(INITIAL_DATA);
  const [previewScore, setPreviewScore] = useState(0);

  // "Manage Categories" mode state
  const [isManagingCategory, setIsManagingCategory] = useState(false);
  const [newCategoryName, setNewCategoryName] = useState('');

  useEffect(() => {
    if (isOpen) {
        if (taskToEdit) {
            // Edit Mode
            setFormData({
                title: taskToEdit.title,
                category: taskToEdit.category,
                dueDate: taskToEdit.dueDate,
                impact: taskToEdit.impact,
                urgency: taskToEdit.urgency,
                effort: taskToEdit.effort,
                isDomino: taskToEdit.isDomino,
                isBlocked: taskToEdit.isBlocked,
            });
        } else {
            // Add Mode
            setFormData({ ...INITIAL_DATA, category: categories[0] || '업무' });
        }
        setIsManagingCategory(false);
        setNewCategoryName('');
    }
  }, [isOpen, taskToEdit, categories]);

  useEffect(() => {
    setPreviewScore(
      calculatePriorityScore(
        formData.impact,
        formData.urgency,
        formData.effort,
        formData.dueDate,
        formData.isDomino,
        formData.isBlocked
      )
    );
  }, [formData]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.title.trim()) return;

    if (taskToEdit && onUpdate) {
        onUpdate(formData);
    } else {
        onAdd(formData);
    }
    onClose();
  };

  const handleAddCategory = () => {
    if (newCategoryName.trim()) {
      onAddCategory(newCategoryName.trim());
      setFormData(prev => ({ ...prev, category: newCategoryName.trim() }));
      setNewCategoryName('');
    }
  };

  const handleSliderChange = (e: React.ChangeEvent<HTMLInputElement>, field: keyof TaskFormData) => {
      setFormData(prev => ({ ...prev, [field]: Number(e.target.value) }));
  };

  if (!isOpen) return null;

  const isEditMode = !!taskToEdit;

  return (
    <AnimatePresence>
      <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          onClick={onClose}
          className="absolute inset-0 bg-zinc-900/40 backdrop-blur-md dark:bg-black/60"
        />

        <motion.div
          initial={{ opacity: 0, scale: 0.95, y: 20 }}
          animate={{ opacity: 1, scale: 1, y: 0 }}
          exit={{ opacity: 0, scale: 0.95, y: 20 }}
          className="relative bg-[#F4F4F5] dark:bg-zinc-900 border border-zinc-200 dark:border-zinc-800 w-full max-w-[500px] rounded-[2.5rem] shadow-2xl overflow-hidden flex flex-col max-h-[90vh]"
        >
          {/* Header */}
          <div className="flex justify-between items-center p-8 pb-4">
              <h2 className="text-4xl font-black text-zinc-900 dark:text-white tracking-tight">
                  {isEditMode ? '탭 수정' : '탭 추가'}
              </h2>
              <button onClick={onClose} className="p-3 rounded-full hover:bg-zinc-200 dark:hover:bg-zinc-800 transition-colors text-zinc-500 dark:text-zinc-400 hover:text-zinc-900 dark:hover:text-white">
                <X size={28} />
              </button>
          </div>

          <form onSubmit={handleSubmit} className="flex-1 px-8 pb-8 flex flex-col gap-6 overflow-y-auto pr-2">

            {/* Title Input */}
            <div>
              <label className="block text-base font-extrabold text-zinc-800 dark:text-zinc-300 mb-2">작업 제목</label>
              <input
                type="text"
                placeholder="할 일을 입력하세요"
                className="w-full bg-white dark:bg-zinc-800 border-2 border-zinc-200 dark:border-zinc-700 rounded-2xl p-5 text-zinc-900 dark:text-white text-xl font-bold placeholder:text-zinc-400 dark:placeholder:text-zinc-600 focus:outline-none focus:ring-4 focus:ring-orange-500/10 focus:border-orange-500 transition-all"
                value={formData.title}
                onChange={e => setFormData({...formData, title: e.target.value})}
                autoFocus={!isManagingCategory && !isEditMode}
              />
            </div>

            {/* Row: Category & Due Date */}
            <div className="flex flex-col gap-5">
                {/* Category Section with Manage Mode */}
                <div>
                    <div className="flex justify-between items-center mb-2">
                        <label className="text-base font-extrabold text-zinc-800 dark:text-zinc-300">카테고리</label>
                        <button 
                            type="button" 
                            onClick={() => setIsManagingCategory(!isManagingCategory)}
                            className={`flex items-center gap-1 text-xs font-bold px-3 py-1 rounded-full transition-colors ${isManagingCategory ? 'bg-orange-100 text-orange-600 dark:bg-orange-900/40 dark:text-orange-400' : 'bg-zinc-200 text-zinc-500 dark:bg-zinc-800 dark:text-zinc-400'}`}
                        >
                            {isManagingCategory ? <Check size={14} /> : <Settings size={14} />}
                            {isManagingCategory ? '완료' : '관리'}
                        </button>
                    </div>

                    {!isManagingCategory ? (
                        // Select Mode
                        <div className="relative">
                           <select
                              className="w-full bg-white dark:bg-zinc-800 border-2 border-zinc-200 dark:border-zinc-700 rounded-2xl p-4 text-lg text-zinc-900 dark:text-white font-bold appearance-none focus:outline-none focus:border-zinc-400"
                              value={formData.category}
                              onChange={e => setFormData({...formData, category: e.target.value})}
                          >
                              {categories.map(c => <option key={c} value={c}>{c}</option>)}
                          </select>
                          <div className="absolute right-3 top-1/2 -translate-y-1/2 flex items-center pointer-events-none text-zinc-500 dark:text-zinc-400">
                             <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4" strokeLinecap="round" strokeLinejoin="round"><path d="m6 9 6 6 6-6"/></svg>
                          </div>
                        </div>
                    ) : (
                        // Manage Mode
                        <div className="bg-white dark:bg-zinc-800 border-2 border-zinc-200 dark:border-zinc-700 rounded-2xl p-4 space-y-4">
                            <div className="flex flex-wrap gap-2">
                                {categories.map(cat => (
                                    <div key={cat} className="flex items-center gap-2 px-3 py-2 bg-zinc-100 dark:bg-zinc-700 rounded-lg group border border-zinc-200 dark:border-zinc-600">
                                        <span className="text-sm font-bold text-zinc-700 dark:text-zinc-200">{cat}</span>
                                        <button 
                                            type="button"
                                            onClick={() => onDeleteCategory(cat)}
                                            className="text-zinc-400 hover:text-red-500 transition-colors"
                                        >
                                            <Trash2 size={14} />
                                        </button>
                                    </div>
                                ))}
                            </div>
                            <div className="flex gap-2">
                                <input 
                                    type="text" 
                                    placeholder="새 카테고리..." 
                                    value={newCategoryName}
                                    onChange={(e) => setNewCategoryName(e.target.value)}
                                    onKeyDown={(e) => e.key === 'Enter' && (e.preventDefault(), handleAddCategory())}
                                    className="flex-1 bg-zinc-50 dark:bg-zinc-900 border border-zinc-300 dark:border-zinc-600 rounded-xl px-3 py-2 text-sm font-bold focus:outline-none focus:border-orange-500 dark:text-white"
                                />
                                <button 
                                    type="button" 
                                    onClick={handleAddCategory}
                                    disabled={!newCategoryName.trim()}
                                    className="bg-zinc-900 dark:bg-white text-white dark:text-zinc-900 rounded-xl px-4 py-2 disabled:opacity-50"
                                >
                                    <Plus size={20} />
                                </button>
                            </div>
                        </div>
                    )}
                </div>

                <div>
                  <label className="block text-base font-extrabold text-zinc-800 dark:text-zinc-300 mb-2">마감일</label>
                  <input
                      type="date"
                      className="w-full bg-white dark:bg-zinc-800 border-2 border-zinc-200 dark:border-zinc-700 rounded-2xl p-4 text-lg text-zinc-900 dark:text-white font-bold focus:outline-none focus:border-zinc-400 invert-calendar-icon"
                      value={formData.dueDate}
                      onChange={e => setFormData({...formData, dueDate: e.target.value})}
                  />
                </div>
            </div>

            {/* Sliders Section */}
            <div className="space-y-6 bg-white dark:bg-zinc-800 p-6 rounded-3xl border border-zinc-200 dark:border-zinc-700 shadow-sm">

              {/* Impact */}
              <div>
                  <div className="flex justify-between mb-3 items-end">
                      <label className="text-lg font-extrabold text-zinc-800 dark:text-zinc-300">영향력</label>
                      <span className="text-base font-black text-orange-500">{formData.impact}/10</span>
                  </div>
                  <input 
                    type="range" min="1" max="10" 
                    value={formData.impact} 
                    onChange={e => handleSliderChange(e, 'impact')} 
                    className="w-full h-3 bg-zinc-200 dark:bg-zinc-600 rounded-full appearance-none cursor-pointer accent-orange-500"
                  />
              </div>

              {/* Urgency */}
              <div>
                  <div className="flex justify-between mb-3 items-end">
                      <label className="text-lg font-extrabold text-zinc-800 dark:text-zinc-300">긴급도</label>
                      <span className="text-base font-black text-orange-500">{formData.urgency}/10</span>
                  </div>
                  <input 
                    type="range" min="1" max="10" 
                    value={formData.urgency} 
                    onChange={e => handleSliderChange(e, 'urgency')} 
                    className="w-full h-3 bg-zinc-200 dark:bg-zinc-600 rounded-full appearance-none cursor-pointer accent-orange-500"
                  />
              </div>

              {/* Effort */}
              <div>
                  <div className="flex justify-between mb-3 items-end">
                      <label className="text-lg font-extrabold text-zinc-800 dark:text-zinc-300">노력/소요</label>
                      <span className="text-base font-black text-zinc-500 dark:text-zinc-400">{formData.effort}/10</span>
                  </div>
                  <input 
                    type="range" min="1" max="10" 
                    value={formData.effort} 
                    onChange={e => handleSliderChange(e, 'effort')} 
                    className="w-full h-3 bg-zinc-200 dark:bg-zinc-600 rounded-full appearance-none cursor-pointer accent-zinc-500"
                  />
              </div>
            </div>

            {/* Core Toggle */}
            <div className="flex items-center justify-between bg-white dark:bg-zinc-800 p-5 rounded-2xl border border-zinc-200 dark:border-zinc-700 shadow-sm cursor-pointer" onClick={() => setFormData({...formData, isDomino: !formData.isDomino})}>
                <span className="text-lg font-extrabold text-zinc-800 dark:text-zinc-300">핵심 과제 여부</span>
                <button
                    type="button"
                    className={`relative w-16 h-9 rounded-full transition-colors duration-200 ease-in-out ${formData.isDomino ? 'bg-orange-500' : 'bg-zinc-300 dark:bg-zinc-600'}`}
                >
                    <span 
                        className={`absolute top-1 left-1 bg-white w-7 h-7 rounded-full shadow-sm transform transition-transform duration-200 ${formData.isDomino ? 'translate-x-7' : 'translate-x-0'}`}
                    />
                </button>
            </div>

            {/* Footer / Score & Save */}
            <div className="mt-auto grid grid-cols-2 gap-4 items-stretch pt-2">
                <button 
                    type="button"
                    onClick={onClose}
                    className="py-5 rounded-2xl border-2 border-zinc-300 dark:border-zinc-700 text-zinc-600 dark:text-zinc-400 font-bold hover:bg-zinc-100 dark:hover:bg-zinc-800 transition-colors text-xl"
                >
                    취소
                </button>
                <div className="relative">
                    <button
                        onClick={handleSubmit}
                        className="w-full h-full py-5 bg-zinc-900 dark:bg-zinc-100 text-white dark:text-zinc-900 font-bold rounded-2xl hover:bg-zinc-800 dark:hover:bg-zinc-200 transition-colors shadow-xl flex flex-col items-center justify-center gap-1 active:scale-95 transform duration-100"
                    >
                        <span className="text-xl">{isEditMode ? '수정 완료' : '추가'}</span>
                        <div className="text-xs opacity-80 font-medium">
                            예상 점수 <span className="text-orange-400 dark:text-orange-600 font-black text-sm ml-1">{previewScore.toFixed(0)}점</span>
                        </div>
                    </button>
                </div>
            </div>

          </form>
        </motion.div>
      </div>
    </AnimatePresence>
  );
};

import React from 'react';
import { Task } from '../types';
import { addDays, parseLocalDate } from '../utils';
import { motion } from 'framer-motion';

interface TimelineProps {
  tasks: Task[];
}

export const Timeline: React.FC<TimelineProps> = ({ tasks }) => {
  const today = new Date();
  today.setHours(0, 0, 0, 0);

  const days = Array.from({ length: 14 }, (_, i) => addDays(today, i));
  const TOTAL_DAYS = 14;

  const relevantTasks = tasks
    .filter(t => !t.isBlocked && !t.isCompleted)
    .sort((a, b) => new Date(a.dueDate).getTime() - new Date(b.dueDate).getTime())
    .slice(0, 7);

  return (
    <div className="h-full flex flex-col min-h-[500px] w-full">

      {relevantTasks.length === 0 ? (
        <div className="flex-1 flex flex-col items-center justify-center text-zinc-500 gap-2 md:gap-4 min-h-[200px]">
             <span className="text-xl md:text-2xl font-bold text-zinc-400 dark:text-zinc-600">일정이 없습니다</span>
        </div>
      ) : (
        <div className="flex-1 flex gap-2 md:gap-4 overflow-hidden relative">
            {/* Task Titles Column */}
            <div className="w-[80px] md:w-[120px] pt-[88px] md:pt-[104px] space-y-8 md:space-y-10 flex-shrink-0 border-r border-zinc-300/50 dark:border-zinc-700/50 pr-2 md:pr-4 bg-transparent z-10">
                {relevantTasks.map(task => (
                    <div key={`title-${task.id}`} className="h-10 md:h-12 flex items-center justify-end">
                        <span className="text-xs md:text-sm font-bold text-zinc-600 dark:text-zinc-400 truncate text-right w-full block" title={task.title}>
                            {task.title}
                        </span>
                    </div>
                ))}
            </div>

            {/* Scrollable Timeline Area */}
            <div className="flex-1 overflow-x-auto relative w-full pb-2">
                <div className="min-w-[700px] md:min-w-[900px] h-full relative flex flex-col">

                    {/* 1. Date Header */}
                    <div 
                        className="grid w-full pb-4 mb-4 md:mb-6 shrink-0"
                        style={{ gridTemplateColumns: `repeat(${TOTAL_DAYS}, 1fr)` }}
                    >
                        {days.map((date, i) => (
                            <div key={i} className="flex flex-col items-center relative group">
                                <span className={`text-[10px] md:text-xs font-extrabold mb-1 uppercase tracking-wider ${i === 0 ? 'text-orange-600' : 'text-zinc-400 group-hover:text-zinc-600 dark:group-hover:text-zinc-300'}`}>
                                    {date.toLocaleDateString('ko-KR', { weekday: 'short' })}
                                </span>
                                <div className={`
                                    w-8 h-8 md:w-10 md:h-10 rounded-full flex items-center justify-center text-sm md:text-lg font-black transition-colors z-20
                                    ${i === 0 ? 'bg-zinc-900 text-white dark:bg-white dark:text-zinc-900 shadow-md' : 'text-zinc-500 bg-transparent group-hover:bg-zinc-200 dark:group-hover:bg-zinc-800'}
                                `}>
                                    {date.getDate()}
                                </div>
                            </div>
                        ))}
                    </div>

                    {/* Content Layer: Grid Lines + Tasks */}
                    <div className="relative flex-1">
                        {/* 2. Grid Lines Background */}
                        <div 
                            className="absolute inset-0 grid pointer-events-none z-0"
                            style={{ gridTemplateColumns: `repeat(${TOTAL_DAYS}, 1fr)` }}
                        >
                             {days.map((_, i) => (
                                <div key={i} className="relative w-full h-full flex justify-center">
                                    {/* Line centered by flexbox */}
                                    <div className="w-px h-full border-l border-dashed border-zinc-300/40 dark:border-zinc-700/40" />
                                </div>
                            ))}
                        </div>

                        {/* 3. Task Rows (Using Grid for Perfect Alignment) */}
                        <div className="relative z-10 space-y-8 md:space-y-10 py-2">
                            {relevantTasks.map((task) => {
                                const taskDue = parseLocalDate(task.dueDate);

                                const timeDiff = taskDue.getTime() - today.getTime();
                                const dayDiff = Math.ceil(timeDiff / (1000 * 3600 * 24));

                                if (dayDiff < 0) return null; 

                                const startIdx = 0; 
                                const endIdx = Math.min(TOTAL_DAYS - 1, dayDiff);
                                const isSameDay = startIdx === endIdx;

                                return (
                                <div 
                                    key={task.id} 
                                    className="relative h-10 md:h-12 w-full grid items-center group"
                                    style={{ gridTemplateColumns: `repeat(${TOTAL_DAYS}, 1fr)` }}
                                >

                                    {/* Connecting Line (Absolute within Grid Row) */}
                                    {!isSameDay && (
                                        <motion.div 
                                            initial={{ opacity: 0, scaleX: 0 }}
                                            animate={{ opacity: 1, scaleX: 1 }}
                                            transition={{ duration: 0.5, delay: 0.2 }}
                                            className="absolute h-[3px] top-1/2 -translate-y-1/2 origin-left bg-zinc-300 dark:bg-zinc-700 z-0 rounded-full"
                                            style={{
                                                left: `${((startIdx + 0.5) / TOTAL_DAYS) * 100}%`, 
                                                width: `${((endIdx - startIdx) / TOTAL_DAYS) * 100}%`,
                                            }}
                                        >
                                            <div className="absolute inset-0 bg-orange-400 dark:bg-orange-500 shadow-[0_0_10px_rgba(251,146,60,0.4)] rounded-full" />
                                        </motion.div>
                                    )}

                                    {/* Start Dot (Placed via Grid Column) */}
                                    <div 
                                        className="relative flex items-center justify-center z-10 pointer-events-none"
                                        style={{ gridColumn: `${startIdx + 1} / span 1`, gridRow: 1 }}
                                    >
                                         <div className="w-2.5 h-2.5 rounded-full bg-orange-500 dark:bg-orange-400 shadow-sm ring-4 ring-white dark:ring-zinc-900 pointer-events-auto" />
                                    </div>

                                    {/* End Circle (Placed via Grid Column) */}
                                    <motion.div 
                                        initial={{ scale: 0 }}
                                        animate={{ scale: 1 }}
                                        transition={{ type: 'spring', stiffness: 300, damping: 20, delay: 0.3 }}
                                        className="relative flex items-center justify-center z-20 pointer-events-none"
                                        style={{ gridColumn: `${endIdx + 1} / span 1`, gridRow: 1 }}
                                    >
                                        <div className="relative flex items-center justify-center pointer-events-auto">
                                            {/* Target Circle */}
                                            <div className={`
                                                w-5 h-5 md:w-6 md:h-6 rounded-full border-[3px] border-orange-500 shadow-md flex items-center justify-center box-border
                                                ${isSameDay ? 'bg-transparent' : 'bg-white dark:bg-zinc-900'}
                                            `}>
                                                 {/* Core Marker (Only if not same day) */}
                                                 {task.isDomino && !isSameDay && <div className="w-1.5 h-1.5 rounded-full bg-orange-500" />}
                                            </div>

                                            {/* Tooltip */}
                                            <div className="absolute bottom-full mb-2 left-1/2 -translate-x-1/2 opacity-0 group-hover:opacity-100 transition-opacity bg-zinc-800 text-white text-[10px] px-2 py-1 rounded whitespace-nowrap pointer-events-none z-30">
                                                {isSameDay ? 'Today' : `D-${dayDiff}`}
                                            </div>
                                        </div>
                                    </motion.div>
                                </div>
                                );
                            })}
                        </div>
                    </div>
                </div>
            </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, ChevronLeft, ChevronRight } from 'lucide-react';
import { Task } from '../types';
import { formatTime } from '../utils';

interface EnergyBillModalProps {
  isOpen: boolean;
  onClose: () => void;
  tasks: Task[];
}

interface DailyStats {
  date: number; // 1-31
  seconds: number;
  cost: number;
}

interface CategoryStats {
  name: string;
  seconds: number;
  cost: number;
}

export const EnergyBillModal: React.FC<EnergyBillModalProps> = ({ isOpen, onClose, tasks }) => {
  const [viewDate, setViewDate] = useState(new Date());

  // Reset to current month when opening
  useEffect(() => {
    if (isOpen) {
      setViewDate(new Date());
    }
  }, [isOpen]);

  const year = viewDate.getFullYear();
  const month = viewDate.getMonth();

  // Calendar Logic
  const daysInMonth = new Date(year, month + 1, 0).getDate();
  const firstDayOfMonth = new Date(year, month, 1).getDay(); // 0 (Sun) - 6 (Sat)

  // Data Aggregation
  const dailyStats: Record<number, DailyStats> = {};
  const categoryStats: Record<string, CategoryStats> = {};
  let totalMonthlySeconds = 0;

  tasks.forEach(task => {
    if (task.workLogs) {
      task.workLogs.forEach(log => {
        const d = new Date(log.startedAt);
        if (d.getFullYear() === year && d.getMonth() === month) {
          const day = d.getDate();

          // Daily Aggregation
          if (!dailyStats[day]) {
            dailyStats[day] = { date: day, seconds: 0, cost: 0 };
          }
          dailyStats[day].seconds += log.duration;
          dailyStats[day].cost += (log.duration / 3600) * 1000;

          // Category Aggregation
          if (!categoryStats[task.category]) {
            categoryStats[task.category] = { name: task.category, seconds: 0, cost: 0 };
          }
          categoryStats[task.category].seconds += log.duration;
          categoryStats[task.category].cost += (log.duration / 3600) * 1000;

          totalMonthlySeconds += log.duration;
        }
      });
    }
  });

  const totalCost = Math.floor((totalMonthlySeconds / 3600) * 1000);
  const categoryList = Object.values(categoryStats).sort((a, b) => b.seconds - a.seconds);

  const prevMonth = () => setViewDate(new Date(year, month - 1, 1));
  const nextMonth = () => setViewDate(new Date(year, month + 1, 1));

  if (!isOpen) return null;

  return (
    <AnimatePresence>
      <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          onClick={onClose}
          className="absolute inset-0 bg-zinc-900/60 backdrop-blur-sm"
        />

        <motion.div
          initial={{ opacity: 0, scale: 0.95, y: 30 }}
          animate={{ opacity: 1, scale: 1, y: 0 }}
          exit={{ opacity: 0, scale: 0.95, y: 30 }}
          className="relative bg-zinc-100 dark:bg-zinc-900 w-full max-w-[1000px] h-[90vh] md:h-[85vh] rounded-[2rem] shadow-2xl overflow-hidden flex flex-col md:flex-row"
        >
           {/* Sidebar / Receipt Summary (Right side on Desktop, Bottom on Mobile) */}
           <div className="md:order-2 w-full md:w-[320px] bg-white dark:bg-zinc-950 border-b md:border-b-0 md:border-l border-zinc-200 dark:border-zinc-800 flex flex-col z-10">
                <div className="p-6 md:p-8 flex-1 overflow-y-auto">

                    {/* Header */}
                    <div className="flex justify-between items-start mb-6">
                        <div>
                            <h2 className="text-2xl font-black text-zinc-900 dark:text-white uppercase tracking-tighter flex items-center gap-2">
                                명세서
                            </h2>
                            <p className="text-zinc-500 dark:text-zinc-400 text-xs font-mono mt-1">
                                {year}.{String(month + 1).padStart(2, '0')} BILLING CYCLE
                            </p>
                        </div>
                        <button onClick={onClose} className="p-2 rounded-full hover:bg-zinc-100 dark:hover:bg-zinc-800 transition-colors">
                            <X size={20} className="text-zinc-500"/>
                        </button>
                    </div>

                    {/* Total Box */}
                    <div className="bg-zinc-50 dark:bg-zinc-900 border-2 border-dashed border-zinc-200 dark:border-zinc-800 rounded-2xl p-6 mb-8 text-center">
                        <span className="text-xs font-bold text-zinc-400 uppercase tracking-widest">Total Value</span>
                        <div className="text-4xl font-black text-zinc-900 dark:text-white mt-2 font-mono">
                            ₩{totalCost.toLocaleString()}
                        </div>
                        <div className="text-xl font-bold text-zinc-500 mt-2">
                            {formatTime(totalMonthlySeconds)}
                        </div>
                    </div>

                    {/* Category Breakdown */}
                    <div className="space-y-6">
                        <h3 className="text-xs font-black text-zinc-400 uppercase tracking-widest flex items-center gap-2">
                            Category Breakdown
                        </h3>

                        <div className="space-y-4">
                            {categoryList.length > 0 ? categoryList.map(cat => {
                                const percent = totalMonthlySeconds > 0 ? (cat.seconds / totalMonthlySeconds) * 100 : 0;
                                return (
                                    <div key={cat.name}>
                                        <div className="flex justify-between text-sm font-bold mb-1 text-zinc-800 dark:text-zinc-200">
                                            <span>{cat.name}</span>
                                            <span>₩{Math.floor(cat.cost).toLocaleString()}</span>
                                        </div>
                                        <div className="w-full h-2 bg-zinc-100 dark:bg-zinc-800 rounded-full overflow-hidden">
                                            <div 
                                                className="h-full bg-orange-500 rounded-full" 
                                                style={{ width: `${percent}%` }}
                                            />
                                        </div>
                                        <div className="text-right text-xs text-zinc-400 mt-1 font-mono font-bold">
                                            {formatTime(cat.seconds)} ({percent.toFixed(1)}%)
                                        </div>
                                    </div>
                                );
                            }) : (
                                <p className="text-zinc-400 text-sm text-center py-4">데이터가 없습니다.</p>
                            )}
                        </div>
                    </div>
                </div>

                {/* Footer Action */}
                <div className="p-6 border-t border-zinc-200 dark:border-zinc-800 bg-zinc-50 dark:bg-zinc-900/50">
                    <button onClick={onClose} className="w-full py-4 bg-zinc-900 dark:bg-white text-white dark:text-zinc-900 rounded-xl font-bold hover:opacity-90 transition-opacity shadow-lg">
                        확인
                    </button>
                </div>
           </div>

           {/* Main Calendar Area (Left/Top) */}
           <div className="md:order-1 flex-1 flex flex-col bg-[#F4F4F5] dark:bg-[#18181B] relative overflow-hidden">

                {/* Calendar Header */}
                <div className="flex items-center justify-between p-6 md:p-8">
                    <div className="flex items-center gap-4">
                        <button onClick={prevMonth} className="p-2 rounded-full bg-white dark:bg-zinc-800 shadow-sm hover:scale-110 transition-transform">
                            <ChevronLeft size={20} className="text-zinc-700 dark:text-zinc-300"/>
                        </button>
                        <h2 className="text-2xl md:text-3xl font-black text-zinc-900 dark:text-white">
                            {year}년 {month + 1}월
                        </h2>
                        <button onClick={nextMonth} className="p-2 rounded-full bg-white dark:bg-zinc-800 shadow-sm hover:scale-110 transition-transform">
                            <ChevronRight size={20} className="text-zinc-700 dark:text-zinc-300"/>
                        </button>
                    </div>
                    <div className="hidden md:flex items-center gap-2 text-zinc-500 text-sm font-bold bg-white dark:bg-zinc-800 px-4 py-2 rounded-full shadow-sm">
                        <span>Daily Power Usage</span>
                    </div>
                </div>

                {/* Calendar Grid */}
                <div className="flex-1 px-4 md:px-8 pb-8 overflow-y-auto">
                    {/* Days Header */}
                    <div className="grid grid-cols-7 mb-2">
                        {['일', '월', '화', '수', '목', '금', '토'].map((d, i) => (
                            <div key={d} className={`text-center text-xs font-black p-2 ${i === 0 ? 'text-orange-500' : 'text-zinc-400'}`}>
                                {d}
                            </div>
                        ))}
                    </div>

                    {/* Days Cells */}
                    <div className="grid grid-cols-7 gap-1 md:gap-3 auto-rows-fr">
                        {/* Empty cells for start of month */}
                        {Array.from({ length: firstDayOfMonth }).map((_, i) => (
                            <div key={`empty-${i}`} className="aspect-square" />
                        ))}

                        {/* Date cells */}
                        {Array.from({ length: daysInMonth }).map((_, i) => {
                            const date = i + 1;
                            const stats = dailyStats[date];
                            const hasData = stats && stats.seconds > 0;

                            // Intensity for background opacity logic (max 8 hours/28800s for full opacity)
                            const intensity = hasData ? Math.min(stats.seconds / 28800, 1) : 0;

                            return (
                                <div 
                                    key={date} 
                                    className={`
                                        relative aspect-square rounded-xl md:rounded-2xl border transition-all group
                                        flex flex-col justify-between p-1.5 md:p-3
                                        ${hasData 
                                            ? 'bg-white dark:bg-zinc-800 border-zinc-200 dark:border-zinc-700 hover:border-orange-500 dark:hover:border-orange-500 shadow-sm' 
                                            : 'bg-transparent border-transparent text-zinc-300 dark:text-zinc-800'
                                        }
                                    `}
                                >
                                    {/* Date Number */}
                                    <span className={`text-sm md:text-lg font-bold ${hasData ? 'text-zinc-900 dark:text-white' : ''}`}>
                                        {date}
                                    </span>

                                    {/* Stats (Only if data exists) */}
                                    {hasData && (
                                        <div className="flex flex-col items-end gap-0.5 md:gap-1">
                                            <span className="text-[10px] md:text-xs font-black text-orange-500">
                                                ₩{Math.floor(stats.cost).toLocaleString()}
                                            </span>
                                            <span className="text-[10px] md:text-xs font-mono font-bold text-zinc-500 dark:text-zinc-400">
                                                {formatTime(stats.seconds)}
                                            </span>
                                        </div>
                                    )}

                                    {/* Background Visual for Intensity */}
                                    {hasData && (
                                        <div 
                                            className="absolute bottom-0 left-0 right-0 h-1 bg-orange-500/20 rounded-b-xl overflow-hidden"
                                        >
                                            <div 
                                                className="h-full bg-orange-500 transition-all duration-1000" 
                                                style={{ width: `${intensity * 100}%` }}
                                            />
                                        </div>
                                    )}
                                </div>
                            );
                        })}
                    </div>
                </div>
           </div>
        </motion.div>
      </div>
    </AnimatePresence>
  );
};

