import React, { useState, useEffect, useRef } from 'react';
import { Plus, Moon, Sun, RotateCcw } from 'lucide-react';
import { Task, TaskFormData, DEFAULT_CATEGORIES } from './types';
import { generateId, calculatePriorityScore, trackEvent } from './utils';
import { MultitapCard } from './components/MultitapCard';
import { TaskDashboard } from './components/TaskDashboard';
import { AddTaskModal } from './components/AddTaskModal';
import { EnergyStats } from './components/EnergyStats';
import { EnergyBillModal } from './components/EnergyBillModal';
import { InstallPrompt } from './components/InstallPrompt';

const App: React.FC = () => {
  const [tasks, setTasks] = useState<Task[]>(() => {
    const saved = localStorage.getItem('core_tab_tasks');
    return saved ? JSON.parse(saved) : [];
  });

  const [categories, setCategories] = useState<string[]>(() => {
      const savedCats = localStorage.getItem('core_tab_categories');
      return savedCats ? JSON.parse(savedCats) : DEFAULT_CATEGORIES;
  });

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isBillModalOpen, setIsBillModalOpen] = useState(false); // New State for Bill Modal
  const [editingTask, setEditingTask] = useState<Task | null>(null);
  const [focusId, setFocusId] = useState<string | null>(null);

  // Track if we have already notified for the current long session
  const hasNotifiedRef = useRef<boolean>(false);

  // Dark Mode State
  const [isDarkMode, setIsDarkMode] = useState<boolean>(() => {
      const savedTheme = localStorage.getItem('core_tab_theme');
      return savedTheme === 'dark';
  });

  // Initialize focusId from saved state on mount if any task is active
  useEffect(() => {
      const activeTask = tasks.find(t => t.isActive);
      if (activeTask) {
          setFocusId(activeTask.id);
      }

      // Request Notification Permission on mount
      if ('Notification' in window && Notification.permission !== 'granted') {
        Notification.requestPermission();
      }
  }, []);

  // Long Focus Check (2 Hours)
  useEffect(() => {
    const checkInterval = setInterval(() => {
        const activeTask = tasks.find(t => t.isActive);

        if (activeTask && activeTask.lastStartTime) {
            const currentDuration = activeTask.totalTime + ((Date.now() - activeTask.lastStartTime) / 1000);
            const TWO_HOURS_IN_SECONDS = 2 * 60 * 60; // 7200 seconds

            // Trigger only if > 2 hours AND haven't notified yet for this specific overflow
            // We use a ref to prevent spamming, but reset it when task changes or stops
            if (currentDuration > TWO_HOURS_IN_SECONDS && !hasNotifiedRef.current) {
                if (Notification.permission === 'granted') {
                    new Notification("Core Tab: 휴식 알림", {
                        body: `"${activeTask.title}" 작업에 2시간 넘게 집중하고 계시네요. 잠시 스트레칭 어때요? ☕️`,
                        icon: "https://i.ibb.co/KzXXK3rZ/core-tab-icon.png"
                    });
                }
                hasNotifiedRef.current = true; // Mark as notified
            }
        } else {
            // No active task, reset the notification flag
            hasNotifiedRef.current = false;
        }
    }, 60000); // Check every 1 minute

    return () => clearInterval(checkInterval);
  }, [tasks]);

  useEffect(() => {
    localStorage.setItem('core_tab_tasks', JSON.stringify(tasks));
  }, [tasks]);

  useEffect(() => {
    localStorage.setItem('core_tab_categories', JSON.stringify(categories));
  }, [categories]);

  useEffect(() => {
      localStorage.setItem('core_tab_theme', isDarkMode ? 'dark' : 'light');
      if (isDarkMode) {
          document.documentElement.classList.add('dark');
      } else {
          document.documentElement.classList.remove('dark');
      }
  }, [isDarkMode]);

  // Handle adding new task
  const addTask = (data: TaskFormData) => {
    const newTask: Task = {
      id: generateId(),
      ...data,
      isCompleted: false,
      isActive: false,
      createdAt: new Date().toISOString(),
      totalTime: 0,
      lastStartTime: null,
      workLogs: [],
    };
    setTasks(prev => [...prev, newTask]);

    // Analytics
    trackEvent('create_task', {
        category: newTask.category,
        score: calculatePriorityScore(newTask.impact, newTask.urgency, newTask.effort, newTask.dueDate, newTask.isDomino, newTask.isBlocked),
        isDomino: newTask.isDomino
    });
  };

  // Handle updating existing task
  const updateTask = (data: TaskFormData) => {
    if (!editingTask) return;

    setTasks(prev => prev.map(t => {
      if (t.id === editingTask.id) {
        return {
          ...t,
          ...data,
          // Preserve these fields
          id: t.id,
          isCompleted: t.isCompleted,
          isActive: t.isActive,
          createdAt: t.createdAt,
          completedAt: t.completedAt,
          totalTime: t.totalTime,
          lastStartTime: t.lastStartTime,
          workLogs: t.workLogs,
        };
      }
      return t;
    }));
    setEditingTask(null);
    trackEvent('update_task', { id: editingTask.id });
  };

  const openAddModal = () => {
    setEditingTask(null);
    setIsModalOpen(true);
  };

  const openEditModal = (task: Task) => {
    setEditingTask(task);
    setIsModalOpen(true);
  };

  const addCategory = (newCat: string) => {
      if (!categories.includes(newCat)) {
          setCategories(prev => [...prev, newCat]);
          trackEvent('add_category', { name: newCat });
      }
  };

  const deleteCategory = (catToDelete: string) => {
      if (categories.length <= 1) {
          alert("최소 하나의 카테고리는 필요합니다.");
          return;
      }
      setCategories(prev => prev.filter(c => c !== catToDelete));
  };

  const toggleFocus = (id: string) => {
    const now = Date.now();

    // Reset notification flag when switching or toggling
    hasNotifiedRef.current = false;

    setTasks(prev => prev.map(t => {
      if (t.id === id) {
        const newState = !t.isActive;
        setFocusId(newState ? id : null);

        if (newState) {
            // Turning ON
            trackEvent('start_focus', { taskId: id, category: t.category });
            return { ...t, isActive: true, lastStartTime: now };
        } else {
            // Turning OFF
            const startTime = t.lastStartTime || now;
            const addedTime = (now - startTime) / 1000;

            trackEvent('end_focus', { taskId: id, duration: addedTime });

            const newLog = {
                startedAt: startTime,
                duration: addedTime
            };

            return { 
                ...t, 
                isActive: false, 
                lastStartTime: null, 
                totalTime: t.totalTime + addedTime,
                workLogs: [...(t.workLogs || []), newLog]
            };
        }
      }

      // If another task was active, turn it off automatically (Mutual Exclusion)
      if (t.isActive) {
          const startTime = t.lastStartTime || now;
          const addedTime = (now - startTime) / 1000;

          trackEvent('end_focus', { taskId: t.id, duration: addedTime, reason: 'switch_task' });

          const newLog = {
            startedAt: startTime,
            duration: addedTime
          };

          return { 
              ...t, 
              isActive: false, 
              lastStartTime: null, 
              totalTime: t.totalTime + addedTime,
              workLogs: [...(t.workLogs || []), newLog] 
          };
      }
      return t;
    }));
  };

  const completeTask = (id: string) => {
    const now = Date.now();
    hasNotifiedRef.current = false; // Reset notification flag

    setTasks(prev => prev.map(t => {
      if (t.id === id) {
          const startTime = t.lastStartTime || now;
          const addedTime = (t.isActive && t.lastStartTime) ? (now - startTime) / 1000 : 0;

          let newLogs = t.workLogs || [];
          if (t.isActive && addedTime > 0) {
              newLogs = [...newLogs, { startedAt: startTime, duration: addedTime }];
              trackEvent('end_focus', { taskId: id, duration: addedTime, reason: 'complete' });
          }

          trackEvent('complete_task', { taskId: id, totalTime: t.totalTime + addedTime });

          return { 
              ...t, 
              isCompleted: true, 
              isActive: false, 
              lastStartTime: null, 
              completedAt: new Date().toISOString(), // Add completion timestamp
              totalTime: t.totalTime + addedTime,
              workLogs: newLogs
          };
      }
      return t;
    }));
    if (focusId === id) setFocusId(null);
  };

  const deleteTask = (id: string) => {
    setTasks(prev => prev.filter(t => t.id !== id));
    trackEvent('delete_task', { taskId: id });
  };

  const resetAllData = () => {
      // Updated confirmation message as requested
      if (window.confirm("지금까지의 탭 내용들이 초기화 됩니다.\n초기화 하시겠습니까?")) {
          trackEvent('reset_data');
          localStorage.clear();
          window.location.reload();
      }
  };

  const getTopTasks = () => {
    const activeTasks = tasks
      .filter(t => !t.isCompleted && !t.isBlocked)
      .sort((a, b) => {
        const scoreA = calculatePriorityScore(a.impact, a.urgency, a.effort, a.dueDate, a.isDomino, a.isBlocked);
        const scoreB = calculatePriorityScore(b.impact, b.urgency, b.effort, b.dueDate, b.isDomino, b.isBlocked);
        return scoreB - scoreA;
      })
      .slice(0, 3);

    const paddedTasks = [...activeTasks];
    while (paddedTasks.length < 3) {
        paddedTasks.push(null as any);
    }
    return paddedTasks;
  };

  const topTasks = getTopTasks();
  const isEmptyState = tasks.length === 0;

  return (
    <div className={isDarkMode ? 'dark' : ''}>
        <div className={`
            bg-[#F4F4F5] dark:bg-[#18181B] 
            p-3 md:p-10 flex flex-col gap-6 md:gap-8 max-w-full mx-auto 
            text-zinc-900 dark:text-zinc-100 
            transition-colors duration-700 
            ${focusId ? 'bg-[#E4E4E7] dark:bg-[#000000]' : ''} 
            min-h-screen
        `}>

        <header className="flex justify-between items-center h-auto md:h-[80px] px-1 md:px-8 z-50 py-3 md:py-0">
            {/* Header Text Logo (Restored) */}
            <div>
                <h1 className="text-xl md:text-4xl font-black tracking-tighter text-zinc-900 dark:text-white leading-none">CORE TAB</h1>
                <p className="text-zinc-600 dark:text-zinc-400 font-bold text-xs md:text-lg mt-0.5 md:mt-1 tracking-wide">Priority Focus System</p>
            </div>

            <div className="flex items-center gap-2 md:gap-4">
                <button 
                    onClick={() => setIsDarkMode(!isDarkMode)}
                    className="p-2 md:p-3 rounded-full bg-zinc-200 dark:bg-zinc-800 text-zinc-700 dark:text-zinc-300 hover:bg-zinc-300 dark:hover:bg-zinc-700 transition-colors"
                    aria-label="Toggle Dark Mode"
                >
                    {isDarkMode ? <Sun size={18} className="md:w-5 md:h-5" /> : <Moon size={18} className="md:w-5 md:h-5" />}
                </button>

                <button 
                onClick={openAddModal}
                className="group flex items-center gap-1.5 md:gap-4 bg-zinc-900 dark:bg-white text-white dark:text-zinc-900 pl-3 pr-4 md:pl-8 md:pr-10 py-2 md:py-5 rounded-full hover:bg-zinc-800 dark:hover:bg-200 transition-all shadow-xl active:scale-95"
                >
                <div className="bg-orange-500 rounded-full p-1 md:p-2">
                    <Plus size={14} className="md:w-6 md:h-6" strokeWidth={4} color="white" />
                </div>
                <span className="font-black tracking-wider text-xs md:text-lg whitespace-nowrap">탭 추가</span>
                </button>
            </div>
        </header>

        {/* MAIN SECTION: Updated to flex-row for mobile to show 3 columns */}
        <main className="flex-1 w-full flex flex-row items-stretch gap-2 md:gap-6 pt-1 md:pt-4 overflow-hidden">
            {topTasks.map((task, index) => {
                const taskId = task ? task.id : `empty-${index}`;
                const isActive = task ? task.isActive : false;
                const isDimmed = focusId !== null && focusId !== taskId;

                return (
                    <MultitapCard 
                    key={taskId} 
                    task={task || undefined} 
                    onToggle={task ? toggleFocus : undefined}
                    onComplete={task ? completeTask : undefined}
                    onAdd={openAddModal}
                    onEdit={task ? openEditModal : undefined}
                    isActive={isActive}
                    isDimmed={isDimmed}
                    />
                );
            })}
        </main>

        {!isEmptyState && (
            <section className={`grid grid-cols-1 lg:grid-cols-2 gap-4 md:gap-10 pb-8 transition-opacity duration-500 items-start ${focusId ? 'opacity-40 pointer-events-none' : 'opacity-100'}`}>
                {/* Left: Unified Dashboard */}
                <TaskDashboard 
                    tasks={tasks} 
                    onDelete={deleteTask} 
                    onEdit={openEditModal}
                />

                {/* Right: Energy Bill Stats */}
                <EnergyStats 
                    tasks={tasks} 
                    onOpenBill={() => setIsBillModalOpen(true)}
                />
            </section>
        )}

        {/* Reset Button Footer - Right Aligned */}
        <footer className="w-full flex justify-end px-4 md:px-10 py-6 mt-auto opacity-50 hover:opacity-100 transition-opacity">
            <button 
                onClick={resetAllData}
                className="flex items-center gap-2 text-xs font-bold text-zinc-400 hover:text-red-500 transition-colors bg-zinc-200 dark:bg-zinc-800 px-4 py-2 rounded-full"
            >
                <RotateCcw size={12} />
                <span>데이터 초기화</span>
            </button>
        </footer>

        <AddTaskModal 
            isOpen={isModalOpen} 
            onClose={() => setIsModalOpen(false)} 
            onAdd={addTask}
            onUpdate={updateTask}
            taskToEdit={editingTask}
            categories={categories}
            onAddCategory={addCategory}
            onDeleteCategory={deleteCategory}
        />

        <EnergyBillModal 
            isOpen={isBillModalOpen}
            onClose={() => setIsBillModalOpen(false)}
            tasks={tasks}
        />

        {/* PWA Install Prompt - Kept as fallback, though Extension is primary now */}
        <InstallPrompt />
        </div>
    </div>
  );
};

export default App;

