import React, { useState, useEffect, useRef } from 'react';
import { Plus, Moon, Sun, RotateCcw, LogOut, LogIn } from 'lucide-react';
import { Task, TaskFormData, DEFAULT_CATEGORIES } from './types';
import { generateId, calculatePriorityScore, trackEvent } from './utils';
import { MultitapCard } from './components/MultitapCard';
import { TaskDashboard } from './components/TaskDashboard';
import { AddTaskModal } from './components/AddTaskModal';
import { EnergyStats } from './components/EnergyStats';
import { EnergyBillModal } from './components/EnergyBillModal';
import { InstallPrompt } from './components/InstallPrompt';

// Firebase Imports
import { auth, googleProvider, db } from './src/firebase';
import { signInWithPopup, signOut, onAuthStateChanged, User } from 'firebase/auth';
import { 
  collection, 
  query, 
  where, 
  onSnapshot, 
  setDoc, 
  deleteDoc, 
  doc, 
  updateDoc 
} from 'firebase/firestore';

const App: React.FC = () => {
  // Auth State
  const [user, setUser] = useState<User | null>(null);
  const [authLoading, setAuthLoading] = useState(true);

  // Data State
  const [tasks, setTasks] = useState<Task[]>([]);
  const [categories, setCategories] = useState<string[]>(DEFAULT_CATEGORIES);

  // UI State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isBillModalOpen, setIsBillModalOpen] = useState(false);
  const [editingTask, setEditingTask] = useState<Task | null>(null);
  const [focusId, setFocusId] = useState<string | null>(null);

  const hasNotifiedRef = useRef<boolean>(false);

  // Dark Mode
  const [isDarkMode, setIsDarkMode] = useState<boolean>(() => {
      return localStorage.getItem('core_tab_theme') === 'dark';
  });

  // 1. Auth Listener
  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, (currentUser) => {
      setUser(currentUser);
      setAuthLoading(false);

      // If no user, we might want to load from localStorage or just show empty
      if (!currentUser) {
         setTasks([]); // Or keep empty to force login
      }
    });
    return () => unsubscribe();
  }, []);

  // 2. Firestore Listener (Real-time Sync)
  useEffect(() => {
    if (!user) return;

    // Listen to Tasks
    const q = query(collection(db, 'tasks'), where('userId', '==', user.uid));
    const unsubscribeTasks = onSnapshot(q, (snapshot) => {
      const loadedTasks: Task[] = [];
      snapshot.forEach((doc) => {
        loadedTasks.push(doc.data() as Task);
      });
      setTasks(loadedTasks);

      // Sync Focus State from DB
      const activeTask = loadedTasks.find(t => t.isActive);
      setFocusId(activeTask ? activeTask.id : null);
    });

    // Listen to Categories (Stored in a user preferences doc or similar)
    // For prototype, we'll simple stick to localStorage for categories OR defaults
    // You could create a 'settings' collection for robust syncing.

    return () => unsubscribeTasks();
  }, [user]);


  // Long Focus Check (2 Hours)
  useEffect(() => {
    const checkInterval = setInterval(() => {
        const activeTask = tasks.find(t => t.isActive);

        if (activeTask && activeTask.lastStartTime) {
            const currentDuration = activeTask.totalTime + ((Date.now() - activeTask.lastStartTime) / 1000);
            const TWO_HOURS_IN_SECONDS = 2 * 60 * 60; 

            if (currentDuration > TWO_HOURS_IN_SECONDS && !hasNotifiedRef.current) {
                if (Notification.permission === 'granted') {
                    new Notification("Core Tab: 휴식 알림", {
                        body: `"${activeTask.title}" 작업에 2시간 넘게 집중하고 계시네요. 잠시 스트레칭 어때요? ☕️`,
                        icon: "https://i.ibb.co/KzXXK3rZ/core-tab-icon.png"
                    });
                }
                hasNotifiedRef.current = true; 
            }
        } else {
            hasNotifiedRef.current = false;
        }
    }, 60000); 

    return () => clearInterval(checkInterval);
  }, [tasks]);

  // Dark Mode Effect
  useEffect(() => {
      localStorage.setItem('core_tab_theme', isDarkMode ? 'dark' : 'light');
      if (isDarkMode) {
          document.documentElement.classList.add('dark');
      } else {
          document.documentElement.classList.remove('dark');
      }
  }, [isDarkMode]);

  // --- Auth Handlers ---
  const handleLogin = async () => {
    try {
      await signInWithPopup(auth, googleProvider);
    } catch (error) {
      console.error("Login failed", error);
      alert("로그인에 실패했습니다. (팝업이 차단되었는지 확인해주세요)");
    }
  };

  const handleLogout = async () => {
    if (confirm("로그아웃 하시겠습니까?")) {
      await signOut(auth);
    }
  };

  // --- Task Handlers (Firestore) ---

  const addTask = async (data: TaskFormData) => {
    if (!user) return;

    const newId = generateId();
    const newTask: Task = {
      id: newId,
      ...data,
      isCompleted: false,
      isActive: false,
      createdAt: new Date().toISOString(),
      totalTime: 0,
      lastStartTime: null,
      workLogs: [],
      userId: user.uid // Add userId for security rules
    };

    // Optimistic UI update is handled by onSnapshot, but we can prevent flicker by writing directly
    await setDoc(doc(db, 'tasks', newId), newTask);

    trackEvent('create_task', { category: newTask.category });
  };

  const updateTask = async (data: TaskFormData) => {
    if (!editingTask || !user) return;

    const taskRef = doc(db, 'tasks', editingTask.id);
    await updateDoc(taskRef, { ...data });

    setEditingTask(null);
    trackEvent('update_task', { id: editingTask.id });
  };

  const toggleFocus = async (id: string) => {
    if (!user) return;

    const now = Date.now();
    hasNotifiedRef.current = false;

    const taskToToggle = tasks.find(t => t.id === id);
    if (!taskToToggle) return;

    if (taskToToggle.isActive) {
        // Turning OFF
        const startTime = taskToToggle.lastStartTime || now;
        const addedTime = (now - startTime) / 1000;
        const newLog = { startedAt: startTime, duration: addedTime };

        await updateDoc(doc(db, 'tasks', id), {
            isActive: false,
            lastStartTime: null,
            totalTime: taskToToggle.totalTime + addedTime,
            workLogs: [...(taskToToggle.workLogs || []), newLog]
        });
        trackEvent('end_focus', { taskId: id });

    } else {
        // Turning ON: Turn off others first (Mutual Exclusion)
        const activeTask = tasks.find(t => t.isActive);
        if (activeTask) {
             const startTime = activeTask.lastStartTime || now;
             const addedTime = (now - startTime) / 1000;
             const newLog = { startedAt: startTime, duration: addedTime };

             await updateDoc(doc(db, 'tasks', activeTask.id), {
                 isActive: false,
                 lastStartTime: null,
                 totalTime: activeTask.totalTime + addedTime,
                 workLogs: [...(activeTask.workLogs || []), newLog]
             });
        }

        // Then Turn ON target
        await updateDoc(doc(db, 'tasks', id), {
            isActive: true,
            lastStartTime: now
        });
        trackEvent('start_focus', { taskId: id });
    }
  };

  const completeTask = async (id: string) => {
    if (!user) return;
    const task = tasks.find(t => t.id === id);
    if (!task) return;

    const now = Date.now();
    const startTime = task.lastStartTime || now;
    const addedTime = (task.isActive && task.lastStartTime) ? (now - startTime) / 1000 : 0;

    let newLogs = task.workLogs || [];
    if (task.isActive && addedTime > 0) {
        newLogs = [...newLogs, { startedAt: startTime, duration: addedTime }];
    }

    await updateDoc(doc(db, 'tasks', id), {
        isCompleted: true,
        isActive: false,
        lastStartTime: null,
        completedAt: new Date().toISOString(),
        totalTime: task.totalTime + addedTime,
        workLogs: newLogs
    });

    trackEvent('complete_task', { taskId: id });
  };

  const deleteTask = async (id: string) => {
    if (!user) return;
    if (confirm("정말 삭제하시겠습니까?")) {
        await deleteDoc(doc(db, 'tasks', id));
        trackEvent('delete_task', { taskId: id });
    }
  };

  const openAddModal = () => {
    setEditingTask(null);
    setIsModalOpen(true);
  };

  const openEditModal = (task: Task) => {
    setEditingTask(task);
    setIsModalOpen(true);
  };

  const addCategory = (newCat: string) => {
      if (!categories.includes(newCat)) {
          setCategories(prev => [...prev, newCat]);
          // Note: In real app, save this to user settings in DB
      }
  };

  const deleteCategory = (catToDelete: string) => {
      if (categories.length <= 1) {
          alert("최소 하나의 카테고리는 필요합니다.");
          return;
      }
      setCategories(prev => prev.filter(c => c !== catToDelete));
  };

  const getTopTasks = () => {
    const activeTasks = tasks
      .filter(t => !t.isCompleted && !t.isBlocked)
      .sort((a, b) => {
        const scoreA = calculatePriorityScore(a.impact, a.urgency, a.effort, a.dueDate, a.isDomino, a.isBlocked);
        const scoreB = calculatePriorityScore(b.impact, b.urgency, b.effort, b.dueDate, b.isDomino, b.isBlocked);
        return scoreB - scoreA;
      })
      .slice(0, 3);

    const paddedTasks = [...activeTasks];
    while (paddedTasks.length < 3) {
        paddedTasks.push(null as any);
    }
    return paddedTasks;
  };

  const topTasks = getTopTasks();
  const isEmptyState = tasks.length === 0;

  // Render Logic
  if (authLoading) {
      return (
          <div className="flex items-center justify-center min-h-screen bg-[#F4F4F5] dark:bg-[#18181B]">
              <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-orange-500"></div>
          </div>
      );
  }

  return (
    <div className={isDarkMode ? 'dark' : ''}>
        <div className={`
            bg-[#F4F4F5] dark:bg-[#18181B] 
            p-3 md:p-10 flex flex-col gap-6 md:gap-8 max-w-full mx-auto 
            text-zinc-900 dark:text-zinc-100 
            transition-colors duration-700 
            ${focusId ? 'bg-[#E4E4E7] dark:bg-[#000000]' : ''} 
            min-h-screen
        `}>

        {/* Header */}
        <header className="flex justify-between items-center h-auto md:h-[80px] px-1 md:px-8 z-50 py-3 md:py-0">
            <div>
                <h1 className="text-xl md:text-4xl font-black tracking-tighter text-zinc-900 dark:text-white leading-none">CORE TAB</h1>
                <p className="text-zinc-600 dark:text-zinc-400 font-bold text-xs md:text-lg mt-0.5 md:mt-1 tracking-wide">Priority Focus System</p>
            </div>

            <div className="flex items-center gap-2 md:gap-4">
                <button 
                    onClick={() => setIsDarkMode(!isDarkMode)}
                    className="p-2 md:p-3 rounded-full bg-zinc-200 dark:bg-zinc-800 text-zinc-700 dark:text-zinc-300 hover:bg-zinc-300 dark:hover:bg-zinc-700 transition-colors"
                >
                    {isDarkMode ? <Sun size={18} className="md:w-5 md:h-5" /> : <Moon size={18} className="md:w-5 md:h-5" />}
                </button>

                {user ? (
                   <div className="flex gap-2">
                        <button 
                            onClick={handleLogout}
                            className="p-2 md:p-3 rounded-full bg-zinc-200 dark:bg-zinc-800 text-zinc-700 dark:text-zinc-300 hover:bg-red-100 hover:text-red-500 transition-colors"
                            title="로그아웃"
                        >
                            <LogOut size={18} className="md:w-5 md:h-5" />
                        </button>
                        <button 
                            onClick={openAddModal}
                            className="group flex items-center gap-1.5 md:gap-4 bg-zinc-900 dark:bg-white text-white dark:text-zinc-900 pl-3 pr-4 md:pl-8 md:pr-10 py-2 md:py-5 rounded-full hover:bg-zinc-800 dark:hover:bg-200 transition-all shadow-xl active:scale-95"
                        >
                            <div className="bg-orange-500 rounded-full p-1 md:p-2">
                                <Plus size={14} className="md:w-6 md:h-6" strokeWidth={4} color="white" />
                            </div>
                            <span className="font-black tracking-wider text-xs md:text-lg whitespace-nowrap">탭 추가</span>
                        </button>
                   </div>
                ) : null}
            </div>
        </header>

        {/* --- Login Screen (If not authenticated) --- */}
        {!user ? (
            <div className="flex-1 flex flex-col items-center justify-center p-8 text-center animate-in fade-in duration-700">
                <div className="max-w-md w-full bg-white dark:bg-zinc-900 rounded-[2.5rem] p-10 shadow-2xl border border-zinc-200 dark:border-zinc-800">
                    <div className="w-20 h-20 bg-zinc-100 dark:bg-zinc-800 rounded-2xl flex items-center justify-center mx-auto mb-6 shadow-inner">
                        <img src="https://i.ibb.co/KzXXK3rZ/core-tab-icon.png" alt="Logo" className="w-14 h-14" />
                    </div>
                    <h2 className="text-3xl font-black mb-3">Login to CoreTab</h2>
                    <p className="text-zinc-500 mb-8 font-medium">PC와 모바일, 어디서든 멀티탭을 동기화하세요.</p>

                    <button 
                        onClick={handleLogin}
                        className="w-full py-4 bg-[#4285F4] hover:bg-[#357ABD] text-white rounded-xl font-bold text-lg flex items-center justify-center gap-3 transition-all shadow-lg active:scale-95"
                    >
                        <div className="bg-white p-1 rounded-full">
                           <svg width="18" height="18" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 48 48"><path fill="#EA4335" d="M24 9.5c3.54 0 6.71 1.22 9.21 3.6l6.85-6.85C35.9 2.38 30.47 0 24 0 14.62 0 6.51 5.38 2.56 13.22l7.98 6.19C12.43 13.72 17.74 9.5 24 9.5z"/><path fill="#4285F4" d="M46.98 24.55c0-1.57-.15-3.09-.38-4.55H24v9.02h12.94c-.58 2.96-2.26 5.48-4.78 7.18l7.73 6c4.51-4.18 7.09-10.36 7.09-17.65z"/><path fill="#FBBC05" d="M10.53 28.59c-.48-1.45-.76-2.99-.76-4.59s.27-3.14.76-4.59l-7.98-6.19C.92 16.46 0 20.12 0 24c0 3.88.92 7.54 2.56 10.78l7.97-6.19z"/><path fill="#34A853" d="M24 48c6.48 0 11.93-2.13 15.89-5.81l-7.73-6c-2.15 1.45-4.92 2.3-8.16 2.3-6.26 0-11.57-4.22-13.47-9.91l-7.98 6.19C6.51 42.62 14.62 48 24 48z"/><path fill="none" d="M0 0h48v48H0z"/></svg>
                        </div>
                        Google 계정으로 계속하기
                    </button>
                    <p className="mt-6 text-xs text-zinc-400">
                        * 초기 설정 시 팝업 차단을 해제해야 할 수 있습니다.
                    </p>
                </div>
            </div>
        ) : (
            // --- Authenticated App ---
            <>
                <main className="flex-1 w-full flex flex-row items-stretch gap-2 md:gap-6 pt-1 md:pt-4 overflow-hidden">
                    {topTasks.map((task, index) => {
                        const taskId = task ? task.id : `empty-${index}`;
                        const isActive = task ? task.isActive : false;
                        const isDimmed = focusId !== null && focusId !== taskId;

                        return (
                            <MultitapCard 
                            key={taskId} 
                            task={task || undefined} 
                            onToggle={task ? toggleFocus : undefined}
                            onComplete={task ? completeTask : undefined}
                            onAdd={openAddModal}
                            onEdit={task ? openEditModal : undefined}
                            isActive={isActive}
                            isDimmed={isDimmed}
                            />
                        );
                    })}
                </main>

                {!isEmptyState && (
                    <section className={`grid grid-cols-1 lg:grid-cols-2 gap-4 md:gap-10 pb-8 transition-opacity duration-500 items-start ${focusId ? 'opacity-40 pointer-events-none' : 'opacity-100'}`}>
                        {/* Left: Unified Dashboard */}
                        <TaskDashboard 
                            tasks={tasks} 
                            onDelete={deleteTask} 
                            onEdit={openEditModal}
                        />

                        {/* Right: Energy Bill Stats */}
                        <EnergyStats 
                            tasks={tasks} 
                            onOpenBill={() => setIsBillModalOpen(true)}
                        />
                    </section>
                )}
            </>
        )}

        <AddTaskModal 
            isOpen={isModalOpen} 
            onClose={() => setIsModalOpen(false)} 
            onAdd={addTask}
            onUpdate={updateTask}
            taskToEdit={editingTask}
            categories={categories}
            onAddCategory={addCategory}
            onDeleteCategory={deleteCategory}
        />

        <EnergyBillModal 
            isOpen={isBillModalOpen}
            onClose={() => setIsBillModalOpen(false)}
            tasks={tasks}
        />

        <InstallPrompt />
        </div>
    </div>
  );
};

export default App;

export interface WorkLog {
  startedAt: number; // Timestamp
  duration: number; // Seconds
}

export interface Task {
  id: string;
  userId?: string; // New field for Firebase ownership
  title: string;
  category: string;
  dueDate: string; // ISO Date string YYYY-MM-DD
  impact: number; // 1-10
  urgency: number; // 1-10
  effort: number; // 1-10
  isDomino: boolean; // Renamed to "My Core" in UI
  isBlocked: boolean; // Pre-requisite penalty
  isCompleted: boolean;
  isActive: boolean; // The "Switch" state
  createdAt: string;
  completedAt?: string; // ISO Date string for completion time
  totalTime: number; // Accumulated time in seconds
  lastStartTime: number | null; // Timestamp when the current session started
  workLogs?: WorkLog[]; // New: History of work sessions
}

export interface TaskFormData {
  title: string;
  category: string;
  dueDate: string;
  impact: number;
  urgency: number;
  effort: number;
  isDomino: boolean;
  isBlocked: boolean;
}

