 * or process.env (fallback/shimmed environments).
 */
const getEnvVar = (key: string): string => {
  try {
    // Attempt Vite-style access first
    if (typeof import.meta !== 'undefined' && (import.meta as any).env) {
      const val = (import.meta as any).env[key];
      if (val) return val;
    }
  } catch (e) {}

  try {
    // Fallback to process.env (often shimmed by servers or proxy layers)
    if (typeof process !== 'undefined' && process.env) {
      const val = (process as any).env[key];
      if (val) return val;
    }
  } catch (e) {}

  return '';
};

